import { authenticatedGet } from '../utils/auth';
import type { CrowdStrikeImportStatus } from '../types/crowdstrike';

/**
 * Service for WG Vulns (Workgroup Vulnerabilities) API operations
 * Feature: 022-wg-vulns-handling
 */

/**
 * Single asset with its vulnerability count
 * Reuses the same interface as Account Vulns for consistency
 */
export interface AssetVulnCount {
  id: number;
  name: string;
  type: string;
  vulnerabilityCount: number;

  // Severity breakdown (optional for backward compatibility)
  criticalCount?: number;
  highCount?: number;
  mediumCount?: number;
}

/**
 * Single workgroup with its assets
 */
export interface WorkgroupGroup {
  workgroupId: number;
  workgroupName: string;
  workgroupDescription?: string;
  assets: AssetVulnCount[];
  totalAssets: number;
  totalVulnerabilities: number;

  // Severity aggregation (optional for backward compatibility)
  totalCritical?: number;
  totalHigh?: number;
  totalMedium?: number;
}

/**
 * Top-level response containing all workgroup groups
 */
export interface WorkgroupVulnsSummary {
  workgroupGroups: WorkgroupGroup[];
  totalAssets: number;
  totalVulnerabilities: number;

  // Global severity totals (optional for backward compatibility)
  globalCritical?: number;
  globalHigh?: number;
  globalMedium?: number;

  // Metadata about the most recent CrowdStrike import
  lastImport?: CrowdStrikeImportStatus | null;
}

/**
 * Admin redirect error response
 */
export interface AdminRedirectError {
  message: string;
  redirectUrl: string;
  status: number;
}

/**
 * Standard error response
 */
export interface ErrorResponse {
  message: string;
  status: number;
}

/**
 * Get vulnerability overview for user's workgroups
 *
 * @returns WorkgroupVulnsSummary with workgroup groups, assets, and vulnerability counts
 * @throws Error if request fails or user has no workgroup memberships
 */
export async function getWorkgroupVulns(): Promise<WorkgroupVulnsSummary> {
  console.log('[workgroupVulnsService] getWorkgroupVulns called');
  console.log('[workgroupVulnsService] Making authenticated GET request to /api/wg-vulns');

  const response = await authenticatedGet('/api/wg-vulns');

  console.log('[workgroupVulnsService] Response received:', {
    ok: response.ok,
    status: response.status,
    statusText: response.statusText,
    headers: Object.fromEntries(response.headers.entries())
  });

  if (!response.ok) {
    console.error('[workgroupVulnsService] Request failed with status:', response.status);
    const errorData = await response.json().catch(() => ({ error: 'Request failed' }));
    console.error('[workgroupVulnsService] Error data:', errorData);
    throw new Error(errorData.error || errorData.message || `Request failed with status ${response.status}`);
  }

  const data = await response.json();
  console.log('[workgroupVulnsService] Successfully parsed response JSON:', data);
  return data;
}

package com.secman.controller

import com.secman.domain.User
import com.secman.dto.CreateUserMappingRequest
import com.secman.dto.UpdateUserMappingRequest
import com.secman.dto.UserMappingResponse
import com.secman.repository.UserRepository
import com.secman.service.UserMappingService
import io.micronaut.data.model.Pageable
import io.micronaut.http.HttpResponse
import io.micronaut.http.HttpStatus
import io.micronaut.http.annotation.*
import io.micronaut.security.annotation.Secured
import io.micronaut.security.rules.SecurityRule
import io.micronaut.serde.annotation.Serdeable
import jakarta.transaction.Transactional
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder

@Controller("/api/users")
@Secured("ADMIN")
open class UserController(
    private val userRepository: UserRepository,
    private val userDeletionValidator: com.secman.service.UserDeletionValidator,
    private val workgroupRepository: com.secman.repository.WorkgroupRepository,
    private val userMappingService: UserMappingService,
    private val adminNotificationService: com.secman.service.AdminNotificationService,
    private val userService: com.secman.service.UserService
) {

    private val passwordEncoder = BCryptPasswordEncoder()

    @Serdeable
    data class CreateUserRequest(
        val username: String,
        val email: String,
        val password: String,
        val roles: List<String>? = null,
        val workgroupIds: List<Long>? = null,
        val mfaEnabled: Boolean? = null
    )

    @Serdeable
    data class UpdateUserRequest(
        val username: String? = null,
        val email: String? = null,
        val password: String? = null,
        val roles: List<String>? = null,
        val workgroupIds: List<Long>? = null,
        val mfaEnabled: Boolean? = null
    )

    @Serdeable
    data class UserResponse(
        val id: Long,
        val username: String,
        val email: String,
        val roles: List<String>,
        val mfaEnabled: Boolean,
        val createdAt: String?,
        val updatedAt: String?,
        val lastLogin: String?,
        val workgroups: List<WorkgroupSummary>? = null,
        val workgroupCount: Int? = null
    ) {
        companion object {
            fun from(user: User, includeWorkgroups: Boolean = false): UserResponse {
                return UserResponse(
                    id = user.id!!,
                    username = user.username,
                    email = user.email,
                    roles = user.roles.map { it.name },
                    mfaEnabled = user.mfaEnabled,
                    createdAt = user.createdAt?.toString(),
                    updatedAt = user.updatedAt?.toString(),
                    lastLogin = user.lastLogin?.toString(),
                    workgroups = if (includeWorkgroups) {
                        user.workgroups.map { WorkgroupSummary(it.id!!, it.name) }
                    } else null,
                    workgroupCount = if (includeWorkgroups) user.workgroups.size else null
                )
            }
        }
    }

    @Serdeable
    data class WorkgroupSummary(
        val id: Long,
        val name: String
    )

    /**
     * List all users with optional workgroup information
     * Feature: 008-create-an-additional (Workgroup-Based Access Control)
     *
     * GET /api/users?includeWorkgroups=true
     * FR-010: Display user workgroup membership in admin views
     */
    @Get
    fun list(@QueryValue(defaultValue = "false") includeWorkgroups: Boolean): HttpResponse<List<UserResponse>> {
        val users = if (includeWorkgroups) {
            userRepository.findAllWithWorkgroups().map { UserResponse.from(it, true) }
        } else {
            userRepository.findAll().map { UserResponse.from(it, false) }
        }
        return HttpResponse.ok(users)
    }

    @Post
    @Transactional
    open fun create(@Body request: CreateUserRequest, authentication: io.micronaut.security.authentication.Authentication): HttpResponse<*> {
        // Validation
        if (request.username.isBlank() || request.email.isBlank() || request.password.isBlank()) {
            return HttpResponse.badRequest(mapOf("error" to "Username, email, and password are required"))
        }

        // Check for duplicates
        if (userRepository.existsByUsername(request.username)) {
            return HttpResponse.badRequest(mapOf("error" to "Username already exists"))
        }

        if (userRepository.existsByEmail(request.email)) {
            return HttpResponse.badRequest(mapOf("error" to "Email already exists"))
        }

        try {
            // Parse roles
            val roles = mutableSetOf<User.Role>()
            request.roles?.forEach { roleString ->
                try {
                    roles.add(User.Role.valueOf(roleString.uppercase()))
                } catch (e: IllegalArgumentException) {
                    return HttpResponse.badRequest(mapOf("error" to "Invalid role: $roleString"))
                }
            }

            // Default to USER, VULN, REQ roles if none provided
            if (roles.isEmpty()) {
                roles.addAll(setOf(User.Role.USER, User.Role.VULN, User.Role.REQ))
            }

            val user = User(
                username = request.username,
                email = request.email,
                passwordHash = passwordEncoder.encode(request.password)!!,
                roles = roles,
                mfaEnabled = request.mfaEnabled ?: false
            )

            val savedUser = userRepository.save(user)

            // Assign workgroups if provided
            request.workgroupIds?.let { workgroupIds ->
                val workgroups = workgroupIds.mapNotNull { id ->
                    workgroupRepository.findById(id).orElse(null)
                }

                if (workgroups.size != workgroupIds.size) {
                    return HttpResponse.badRequest(mapOf("error" to "One or more workgroup IDs not found"))
                }

                savedUser.workgroups.clear()
                savedUser.workgroups.addAll(workgroups)
                userRepository.update(savedUser)
            }

            // Send email notification to ADMIN users (async, non-blocking)
            // Feature: 027-admin-user-notifications
            try {
                val createdByUsername = authentication.name
                adminNotificationService.sendNewUserNotificationForManualCreation(savedUser, createdByUsername)
            } catch (e: Exception) {
                // Log but don't fail user creation if notification fails
                // Notification failures are already logged in AdminNotificationService
            }

            return HttpResponse.ok(UserResponse.from(savedUser, includeWorkgroups = true))

        } catch (e: Exception) {
            return HttpResponse.serverError<Any>().body(mapOf("error" to "Failed to create user: ${e.message}"))
        }
    }

    /**
     * Get user by ID with workgroup information
     * Feature: 008-create-an-additional (Workgroup-Based Access Control)
     *
     * GET /api/users/{id}
     * FR-010: Display user workgroup membership in detail views
     */
    @Get("/{id}")
    fun get(@PathVariable id: Long): HttpResponse<*> {
        val userOptional = userRepository.findByIdWithWorkgroups(id)

        if (userOptional.isEmpty) {
            return HttpResponse.notFound<Any>().body(mapOf("error" to "User not found"))
        }

        // Always include workgroups in detail view
        return HttpResponse.ok(UserResponse.from(userOptional.get(), includeWorkgroups = true))
    }

    @Put("/{id}")
    @Transactional
    open fun update(@PathVariable id: Long, @Body request: UpdateUserRequest): HttpResponse<*> {
        val userOptional = userRepository.findById(id)

        if (userOptional.isEmpty) {
            return HttpResponse.notFound<Any>().body(mapOf("error" to "User not found"))
        }

        val user = userOptional.get()

        try {
            // Update fields if provided
            request.username?.let { 
                if (it.isNotBlank() && it != user.username) {
                    if (userRepository.existsByUsername(it)) {
                        return HttpResponse.badRequest(mapOf("error" to "Username already exists"))
                    }
                    user.username = it
                }
            }

            request.email?.let { 
                if (it.isNotBlank() && it != user.email) {
                    if (userRepository.existsByEmail(it)) {
                        return HttpResponse.badRequest(mapOf("error" to "Email already exists"))
                    }
                    user.email = it
                }
            }

            request.password?.let {
                if (it.isNotBlank()) {
                    user.passwordHash = passwordEncoder.encode(it)!!
                }
            }

            request.mfaEnabled?.let {
                user.mfaEnabled = it
            }

            request.roles?.let { roleStrings ->
                val roles = mutableSetOf<User.Role>()
                roleStrings.forEach { roleString ->
                    try {
                        roles.add(User.Role.valueOf(roleString.uppercase()))
                    } catch (e: IllegalArgumentException) {
                        return HttpResponse.badRequest(mapOf("error" to "Invalid role: $roleString"))
                    }
                }

                // Feature 037: Validate admin role removal
                val roleValidation = userDeletionValidator.validateAdminRoleRemoval(id, roles)
                if (!roleValidation.canDelete) {
                    val response = mapOf(
                        "error" to "Cannot update user",
                        "message" to roleValidation.message,
                        "blockingReferences" to roleValidation.blockingReferences.map { ref ->
                            mapOf(
                                "entityType" to ref.entityType,
                                "count" to ref.count,
                                "role" to ref.role,
                                "details" to ref.details
                            )
                        }
                    )
                    return HttpResponse.status<Any>(HttpStatus.CONFLICT).body(response)
                }

                // Properly manage the collection instead of replacing it
                user.roles.clear()
                user.roles.addAll(roles)
            }

            request.workgroupIds?.let { workgroupIds ->
                val workgroups = workgroupIds.mapNotNull { id ->
                    workgroupRepository.findById(id).orElse(null)
                }

                if (workgroups.size != workgroupIds.size) {
                    return HttpResponse.badRequest(mapOf("error" to "One or more workgroup IDs not found"))
                }

                // Update workgroup assignments
                user.workgroups.clear()
                user.workgroups.addAll(workgroups)
            }

            val savedUser = userRepository.update(user)
            return HttpResponse.ok(UserResponse.from(savedUser, includeWorkgroups = true))

        } catch (e: Exception) {
            return HttpResponse.serverError<Any>().body(mapOf("error" to "Failed to update user: ${e.message}"))
        }
    }

    @Delete("/{id}")
    open fun delete(@PathVariable id: Long): HttpResponse<*> {
        val userOptional = userRepository.findById(id)

        if (userOptional.isEmpty) {
            return HttpResponse.notFound<Any>().body(mapOf("error" to "User not found"))
        }

        // Validate user deletion
        val validationResult = userDeletionValidator.validateUserDeletion(id)

        if (!validationResult.canDelete) {
            // Return detailed error with blocking references
            val response = mapOf(
                "error" to "Cannot delete user",
                "message" to validationResult.message,
                "blockingReferences" to validationResult.blockingReferences.map { ref ->
                    mapOf(
                        "entityType" to ref.entityType,
                        "count" to ref.count,
                        "role" to ref.role,
                        "details" to ref.details
                    )
                }
            )
            // Feature 037: Return 409 Conflict for last admin protection (SystemConstraint)
            // Return 400 Bad Request for other blocking references (demands, risk assessments, etc.)
            val isLastAdminProtection = validationResult.blockingReferences.any { it.entityType == "SystemConstraint" }
            return if (isLastAdminProtection) {
                HttpResponse.status<Any>(HttpStatus.CONFLICT).body(response)
            } else {
                HttpResponse.badRequest<Any>().body(response)
            }
        }

        try {
            userService.deleteUser(id)
            return HttpResponse.ok(mapOf("message" to "User deleted successfully"))
        } catch (e: Exception) {
            return HttpResponse.serverError<Any>().body(mapOf("error" to "Failed to delete user: ${e.message}"))
        }
    }

    // User Mapping Management Endpoints (Feature 017)

    /**
     * Get all mappings for a user
     * Feature: 017-user-mapping-management
     * User Story 1: View User's Existing Mappings (P1)
     */
    @Get("/{userId}/mappings")
    fun getUserMappings(@PathVariable userId: Long): List<UserMappingResponse> {
        return userMappingService.getUserMappings(userId)
    }

    /**
     * Create a new mapping for a user
     * Feature: 017-user-mapping-management
     * User Story 2: Add New Mapping (P2)
     */
    @Post("/{userId}/mappings")
    @Status(HttpStatus.CREATED)
    fun createUserMapping(
        @PathVariable userId: Long,
        @Body request: CreateUserMappingRequest
    ): UserMappingResponse {
        return userMappingService.createMapping(userId, request)
    }

    /**
     * Update an existing mapping
     * Feature: 017-user-mapping-management
     * User Story 4: Edit Existing Mapping (P3)
     */
    @Put("/{userId}/mappings/{mappingId}")
    fun updateUserMapping(
        @PathVariable userId: Long,
        @PathVariable mappingId: Long,
        @Body request: UpdateUserMappingRequest
    ): UserMappingResponse {
        return userMappingService.updateMapping(userId, mappingId, request)
    }

    /**
     * Delete a mapping
     * Feature: 017-user-mapping-management
     * User Story 3: Delete Existing Mapping (P2)
     */
    @Delete("/{userId}/mappings/{mappingId}")
    @Status(HttpStatus.NO_CONTENT)
    fun deleteUserMapping(
        @PathVariable userId: Long,
        @PathVariable mappingId: Long
    ) {
        userMappingService.deleteMapping(userId, mappingId)
    }
}

package com.secman.controller

import com.secman.domain.User
import com.secman.dto.UserProfileDto
import com.secman.repository.UserRepository
import com.secman.service.AuditLogService
import com.secman.service.WebAuthnService
import io.micronaut.http.HttpResponse
import io.micronaut.http.HttpStatus
import io.micronaut.http.annotation.*
import io.micronaut.security.annotation.Secured
import io.micronaut.security.authentication.Authentication
import io.micronaut.security.rules.SecurityRule
import io.micronaut.serde.annotation.Serdeable
import jakarta.transaction.Transactional
import org.slf4j.LoggerFactory
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder

/**
 * Controller for user profile operations
 * Feature 028: User Profile Page
 * Feature 051: User Password Change
 *
 * Endpoints:
 * - GET /api/users/profile: Returns current user's profile data
 * - PUT /api/users/profile/change-password: Changes current user's password
 *
 * Security: All endpoints require authentication
 */
@Controller("/api/users")
@Secured(SecurityRule.IS_AUTHENTICATED)
open class UserProfileController(
    private val userRepository: UserRepository,
    private val webAuthnService: WebAuthnService,
    private val auditLogService: AuditLogService
) {
    private val logger = LoggerFactory.getLogger(UserProfileController::class.java)
    private val passwordEncoder = BCryptPasswordEncoder()

    @Serdeable
    data class ErrorResponse(
        val message: String
    )

    @Serdeable
    data class MfaToggleRequest(
        val enabled: Boolean
    )

    @Serdeable
    data class MfaStatusResponse(
        val enabled: Boolean,
        val passkeyCount: Int,
        val canDisable: Boolean,
        val message: String? = null
    )

    /**
     * Request DTO for password change
     * Feature 051: User Password Change
     */
    @Serdeable
    data class ChangePasswordRequest(
        val currentPassword: String,
        val newPassword: String,
        val confirmPassword: String
    )

    /**
     * Response DTO for password change
     * Feature 051: User Password Change
     */
    @Serdeable
    data class ChangePasswordResponse(
        val success: Boolean,
        val message: String
    )

    /**
     * Get current user's profile
     *
     * Retrieves profile information (username, email, roles) for the authenticated user.
     * User is identified from the JWT token in the Authorization header.
     *
     * @param authentication Micronaut Security authentication object
     * @return HttpResponse with UserProfileDto or 404 error
     */
    @Get("/profile")
    fun getCurrentUserProfile(authentication: Authentication): HttpResponse<*> {
        val username = authentication.name
        logger.debug("Fetching profile for user: {}", username)

        val userOptional = userRepository.findByUsername(username)
        if (userOptional.isEmpty) {
            logger.warn("User not found: {}", username)
            return HttpResponse.notFound(ErrorResponse("User not found"))
        }

        val user = userOptional.get()
        logger.debug("Profile retrieved for user: {}", username)
        return HttpResponse.ok(UserProfileDto.fromUser(user))
    }

    /**
     * Get MFA status for current user
     * Feature: Passkey MFA Support
     *
     * GET /api/users/profile/mfa-status
     */
    @Get("/profile/mfa-status")
    fun getMfaStatus(authentication: Authentication): HttpResponse<*> {
        try {
            val username = authentication.name
            val user = userRepository.findByUsername(username).orElseThrow {
                IllegalArgumentException("User not found")
            }

            val passkeys = webAuthnService.getUserPasskeys(user)
            val passkeyCount = passkeys.size

            val response = MfaStatusResponse(
                enabled = user.mfaEnabled,
                passkeyCount = passkeyCount,
                canDisable = passkeyCount == 0 || !user.mfaEnabled,
                message = when {
                    user.mfaEnabled && passkeyCount == 0 -> "MFA is enabled but no passkeys are registered. Please register a passkey."
                    user.mfaEnabled && passkeyCount > 0 -> "MFA is enabled with $passkeyCount passkey(s) registered."
                    !user.mfaEnabled && passkeyCount > 0 -> "MFA is disabled. You have $passkeyCount passkey(s) registered but not actively used."
                    else -> "MFA is disabled. Register a passkey to enable MFA."
                }
            )

            return HttpResponse.ok(response)

        } catch (e: Exception) {
            logger.error("Failed to get MFA status", e)
            return HttpResponse.badRequest(mapOf("error" to "Failed to get MFA status: ${e.message}"))
        }
    }

    /**
     * Toggle MFA on/off for current user
     * Feature: Passkey MFA Support
     *
     * PUT /api/users/profile/mfa-toggle
     */
    @Put("/profile/mfa-toggle")
    @Transactional
    open fun toggleMfa(
        @Body request: MfaToggleRequest,
        authentication: Authentication
    ): HttpResponse<*> {
        try {
            val username = authentication.name
            val user = userRepository.findByUsername(username).orElseThrow {
                IllegalArgumentException("User not found")
            }

            // Check if user has passkeys when enabling MFA
            if (request.enabled) {
                val passkeyCount = webAuthnService.getUserPasskeys(user).size
                if (passkeyCount == 0) {
                    return HttpResponse.badRequest(mapOf(
                        "error" to "Cannot enable MFA without registering at least one passkey",
                        "message" to "Please register a passkey before enabling MFA"
                    ))
                }
            }

            user.mfaEnabled = request.enabled
            userRepository.update(user)

            logger.info("User ${user.username} (ID: ${user.id}) ${if (request.enabled) "enabled" else "disabled"} MFA")

            return HttpResponse.ok(mapOf(
                "success" to true,
                "mfaEnabled" to user.mfaEnabled,
                "message" to "MFA ${if (request.enabled) "enabled" else "disabled"} successfully"
            ))

        } catch (e: Exception) {
            logger.error("Failed to toggle MFA", e)
            return HttpResponse.badRequest(mapOf("error" to "Failed to toggle MFA: ${e.message}"))
        }
    }

    /**
     * Change current user's password
     * Feature 051: User Password Change
     *
     * PUT /api/users/profile/change-password
     *
     * Requirements:
     * - FR-001: Accessible to authenticated users with local accounts
     * - FR-002: Requires current password verification
     * - FR-003, FR-004: Requires new password and confirmation to match
     * - FR-005: Minimum 8 characters
     * - FR-006: Must differ from current password
     * - FR-007: Clear error messages
     * - FR-008: Success message on completion
     * - FR-009: OAuth users cannot change password
     * - FR-010: Secure password hashing
     */
    @Put("/profile/change-password")
    @Transactional
    open fun changePassword(
        @Body request: ChangePasswordRequest,
        authentication: Authentication
    ): HttpResponse<*> {
        val username = authentication.name
        logger.debug("Password change request for user: {}", username)

        // Find user
        val userOptional = userRepository.findByUsername(username)
        if (userOptional.isEmpty) {
            logger.warn("Password change attempted for non-existent user: {}", username)
            return HttpResponse.notFound(ChangePasswordResponse(false, "User not found"))
        }

        val user = userOptional.get()

        // FR-009: Check if user can change password (not OAuth-only)
        if (user.authSource == User.AuthSource.OAUTH) {
            logger.warn("OAuth user {} attempted to change password", username)
            // FR-011: Audit log failed attempt
            auditLogService.logAction(
                authentication = authentication,
                action = "PASSWORD_CHANGE_FAILED",
                entityType = "User",
                entityId = user.id,
                details = "OAuth user attempted password change"
            )
            return HttpResponse.status<ChangePasswordResponse>(HttpStatus.FORBIDDEN)
                .body(ChangePasswordResponse(false, "Password change is not available for OAuth accounts"))
        }

        // FR-002: Verify current password
        if (!passwordEncoder.matches(request.currentPassword, user.passwordHash)) {
            logger.warn("Invalid current password for user: {}", username)
            // FR-011: Audit log failed attempt
            auditLogService.logAction(
                authentication = authentication,
                action = "PASSWORD_CHANGE_FAILED",
                entityType = "User",
                entityId = user.id,
                details = "Invalid current password provided"
            )
            return HttpResponse.badRequest(ChangePasswordResponse(false, "Current password is incorrect"))
        }

        // FR-003, FR-004: Verify new password and confirmation match
        if (request.newPassword != request.confirmPassword) {
            return HttpResponse.badRequest(ChangePasswordResponse(false, "New password and confirmation do not match"))
        }

        // FR-005: Minimum length validation
        if (request.newPassword.length < 8) {
            return HttpResponse.badRequest(ChangePasswordResponse(false, "Password must be at least 8 characters"))
        }

        // FR-020 (from US2): Max length validation
        if (request.newPassword.length > 200) {
            return HttpResponse.badRequest(ChangePasswordResponse(false, "Password exceeds maximum length"))
        }

        // FR-006: Must differ from current password
        if (passwordEncoder.matches(request.newPassword, user.passwordHash)) {
            return HttpResponse.badRequest(ChangePasswordResponse(false, "New password must be different from current password"))
        }

        // FR-010: Update password with secure hashing
        user.passwordHash = passwordEncoder.encode(request.newPassword)!!
        userRepository.update(user)

        logger.info("Password changed successfully for user: {} (ID: {})", username, user.id)

        // FR-011: Audit log successful password change
        auditLogService.logAction(
            authentication = authentication,
            action = "PASSWORD_CHANGED",
            entityType = "User",
            entityId = user.id,
            details = "Password changed successfully via self-service"
        )

        // FR-008: Success message
        return HttpResponse.ok(ChangePasswordResponse(true, "Password changed successfully"))
    }
}

