                                {!isAdmin && (
                                    <li>
                                        <a href="/vulnerabilities/domain" className="d-flex align-items-center p-2 text-dark text-decoration-none rounded hover-bg-secondary">
                                            <i className="bi bi-globe me-2"></i> Domain vulns
