                            VULNERABILITY MANAGEMENT
                            <i className={`bi ${vulnMenuOpen ? 'bi-chevron-down' : 'bi-chevron-right'} ms-auto`}></i>
                        </div>
                        {vulnMenuOpen && (
                            <ul className="list-unstyled ps-4">
                                {/* Overview - ADMIN or SECCHAMPION only */}
